from __future__ import annotations

import argparse
import sys
import os

from gi.repository import GLib, Gio


# ── D-Bus constants ───────────────────────────────────────────────────────────

SS_BUS      = "org.freedesktop.secrets"
SS_PATH     = "/org/freedesktop/secrets"
SS_SERVICE  = "org.freedesktop.Secret.Service"
SS_COLL     = "org.freedesktop.Secret.Collection"
SS_ITEM     = "org.freedesktop.Secret.Item"
SS_SESSION  = "org.freedesktop.Secret.Session"
SS_PROMPT   = "org.freedesktop.Secret.Prompt"
DBUS_INTRO  = "org.freedesktop.DBus.Introspectable"

DEFAULT_COLLECTION = "/org/freedesktop/secrets/aliases/default"


# ── Proxy helpers ─────────────────────────────────────────────────────────────

def _make_proxy(iface: str, path: str) -> Gio.DBusProxy:
    """Create a synchronous DBusProxy for the given interface and object path."""
    return Gio.DBusProxy.new_for_bus_sync(
        Gio.BusType.SESSION,
        Gio.DBusProxyFlags.NONE,
        None,           # GDBusInterfaceInfo — None means no pre-validation
        SS_BUS,
        path,
        iface,
        None,           # GCancellable
    )


def _call(proxy: Gio.DBusProxy,
          method: str,
          args: GLib.Variant,
          reply_type: str | None = None) -> GLib.Variant | None:
    """Call a method on a DBusProxy and return the result Variant."""
    return proxy.call_sync(
        method, args,
        Gio.DBusCallFlags.NONE, -1, None,
    )


def _get_prop(proxy: Gio.DBusProxy, prop: str):
    """
    Read a property from a DBusProxy.  Tries the cached value first;
    falls back to a live Get call if not cached.
    """
    cached = proxy.get_cached_property(prop)
    if cached is not None:
        return cached.unpack()
    # Fallback: call org.freedesktop.DBus.Properties.Get directly
    result = proxy.call_sync(
        "org.freedesktop.DBus.Properties.Get",
        GLib.Variant("(ss)", (proxy.get_interface_name(), prop)),
        Gio.DBusCallFlags.NONE, -1, None,
    )
    return result[0]


def _prompt_if_needed(prompt_path: str) -> None:
    """Trigger and wait for a Secret Service unlock prompt if required."""
    if prompt_path == "/":
        return

    loop   = GLib.MainLoop()
    result = [None]
    conn   = Gio.bus_get_sync(Gio.BusType.SESSION, None)

    def on_completed(conn2, sender, obj_path, iface, signal, params, user_data):
        dismissed, _res = params
        result[0] = dismissed
        loop.quit()

    sub_id = conn.signal_subscribe(
        SS_BUS, SS_PROMPT, "Completed",
        prompt_path, None,
        Gio.DBusSignalFlags.NONE,
        on_completed, None,
    )
    prompt_proxy = _make_proxy(SS_PROMPT, prompt_path)
    _call(prompt_proxy, "Prompt", GLib.Variant("(s)", ("",)))
    GLib.timeout_add_seconds(60, loop.quit)
    loop.run()
    conn.signal_unsubscribe(sub_id)

    if result[0]:
        raise RuntimeError("Unlock prompt was dismissed.")


def _open_session() -> tuple[Gio.DBusProxy, str]:
    """
    Open a Secret Service session using the 'plain' algorithm.
    Returns (service_proxy, session_object_path).
    """
    svc = _make_proxy(SS_SERVICE, SS_PATH)
    result = _call(
        svc, "OpenSession",
        GLib.Variant("(sv)", ("plain", GLib.Variant("s", ""))),
    )
    # result is (algorithm_output_variant, session_object_path)
    session_path = result[1]
    return svc, session_path


def _unlock_collection(svc: Gio.DBusProxy, collection_path: str) -> None:
    """Unlock the collection, triggering a prompt if required."""
    coll = _make_proxy(SS_COLL, collection_path)
    locked = _get_prop(coll, "Locked")
    if not locked:
        return

    result = _call(
        svc, "Unlock",
        GLib.Variant("(ao)", ([collection_path],)),
    )
    prompt_path = result[1]
    _prompt_if_needed(prompt_path)

    # Re-check
    coll2 = _make_proxy(SS_COLL, collection_path)
    if _get_prop(coll2, "Locked"):
        raise RuntimeError(
            "Collection is still locked after unlock attempt. "
            "The Secret Service provider may be closed or the unlock was cancelled."
        )


def _list_item_paths(collection_path: str) -> list[str]:
    """Return all item object paths in the collection."""
    coll = _make_proxy(SS_COLL, collection_path)
    return list(_get_prop(coll, "Items"))


def _item_label(item_path: str) -> str:
    """Return the Label property of an item."""
    item = _make_proxy(SS_ITEM, item_path)
    return str(_get_prop(item, "Label"))


def _item_attributes(item_path: str) -> dict[str, str]:
    """Return the Attributes dict of an item."""
    item = _make_proxy(SS_ITEM, item_path)
    raw = _get_prop(item, "Attributes")
    # raw is already a dict[str, str] after unpack()
    return dict(raw) if raw else {}


def _item_secret(item_path: str, session_path: str, svc: Gio.DBusProxy) -> str:
    """
    Retrieve and decode the secret for one item.
    If the item is locked (KeePassXC requires per-item authorization),
    unlock it via the service — which triggers the KeePassXC approval
    dialog — then retry.
    """
    item = _make_proxy(SS_ITEM, item_path)
    try:
        result = _call(
            item, "GetSecret",
            GLib.Variant("(o)", (session_path,)),
        )
    except Exception as exc:
        if "IsLocked" not in str(exc):
            raise
        # Item requires explicit unlock (KeePassXC per-item authorization).
        # This is what triggers the KeePassXC "Allow access?" dialog.
        unlock_result = _call(
            svc, "Unlock",
            GLib.Variant("(ao)", ([item_path],)),
        )
        prompt_path = unlock_result[1]
        _prompt_if_needed(prompt_path)
        # Retry after authorization
        item   = _make_proxy(SS_ITEM, item_path)
        result = _call(
            item, "GetSecret",
            GLib.Variant("(o)", (session_path,)),
        )
    # Secret struct: (session_path, parameters, value_bytes, content_type)
    secret_bytes = bytes(result[0][2])
    return secret_bytes.decode("utf-8")


# ── Commands ──────────────────────────────────────────────────────────────────

def cmd_introspect(args) -> int:
    """Print raw introspection XML for the Secret Service root object."""
    print(f"Introspecting {SS_BUS} at {SS_PATH} ...")
    print()
    try:
        conn = Gio.bus_get_sync(Gio.BusType.SESSION, None)
        result = conn.call_sync(
            SS_BUS, SS_PATH,
            DBUS_INTRO, "Introspect",
            GLib.Variant("()", ()),
            GLib.VariantType("(s)"),
            Gio.DBusCallFlags.NONE, -1, None,
        )
        print(result[0])
        return 0
    except Exception as exc:
        print(f"ERROR: {exc}", file=sys.stderr)
        print(
            "\nIs the Secret Service provider running?  "
            "For KeePassXC: ensure it is open and Secret Service Integration "
            "is enabled (Tools → Settings → Secret Service Integration).",
            file=sys.stderr,
        )
        return 1


def cmd_list(args) -> int:
    """List all items in the collection with their labels and attributes."""
    collection_path = args.collection

    print(f"Opening Secret Service session ...")
    try:
        svc, session_path = _open_session()
    except Exception as exc:
        print(f"ERROR opening session: {exc}", file=sys.stderr)
        return 1

    print(f"Session opened: {session_path}")
    print(f"Unlocking collection: {collection_path} ...")

    try:
        _unlock_collection(svc, collection_path)
    except Exception as exc:
        print(f"ERROR unlocking collection: {exc}", file=sys.stderr)
        return 1

    print("Collection unlocked.")

    try:
        item_paths = _list_item_paths(collection_path)
    except Exception as exc:
        print(f"ERROR listing items: {exc}", file=sys.stderr)
        return 1

    print(f"\nFound {len(item_paths)} item(s):\n")

    # Collect (label, attributes, path) for sorting
    items = []
    for path in item_paths:
        try:
            label = _item_label(path)
            attrs = _item_attributes(path)
            items.append((label, attrs, path))
        except Exception as exc:
            items.append((f"(unreadable: {exc})", {}, path))

    items.sort(key=lambda t: t[0].lower())

    for label, attrs, path in items:
        username = attrs.get("UserName", attrs.get("username", ""))
        if args.verbose:
            print(f"  Label   : {label}")
            print(f"  Path    : {path}")
            for k, v in sorted(attrs.items()):
                print(f"  {k:<12}: {v}")
            print()
        else:
            user_part = f"  (UserName: {username})" if username else ""
            print(f"  {label}{user_part}")

    # Close session
    try:
        sess = _make_proxy(SS_SESSION, session_path)
        _call(sess, "Close", GLib.Variant("()", ()))
    except Exception:
        pass

    return 0


def cmd_lookup(args) -> int:
    """Look up a secret by label and print it."""
    key             = args.key
    collection_path = args.collection

    print(f"Looking up: {key!r}")

    try:
        svc, session_path = _open_session()
    except Exception as exc:
        print(f"ERROR opening session: {exc}", file=sys.stderr)
        return 1

    try:
        _unlock_collection(svc, collection_path)
    except Exception as exc:
        print(f"ERROR unlocking collection: {exc}", file=sys.stderr)
        return 1

    try:
        item_paths = _list_item_paths(collection_path)
    except Exception as exc:
        print(f"ERROR listing items: {exc}", file=sys.stderr)
        return 1

    found_path = None
    for path in item_paths:
        try:
            if _item_label(path) == key:
                found_path = path
                break
        except Exception:
            continue

    if found_path is None:
        print(f"ERROR: No item found with label {key!r}.", file=sys.stderr)
        print(
            "Use 'list' to see all available labels.",
            file=sys.stderr,
        )
        try:
            sess = _make_proxy(SS_SESSION, session_path)
            _call(sess, "Close", GLib.Variant("()", ()))
        except Exception:
            pass
        return 1

    try:
        secret = _item_secret(found_path, session_path, svc)
    except Exception as exc:
        print(f"ERROR retrieving secret: {exc}", file=sys.stderr)
        return 1
    finally:
        try:
            sess = _make_proxy(SS_SESSION, session_path)
            _call(sess, "Close", GLib.Variant("()", ()))
        except Exception:
            pass

    print(f"Secret for {key!r}: {secret}")
    return 0


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="kwin_secret_service.py",
        description="Diagnostic tool for the org.freedesktop.secrets Secret Service protocol.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=(
            "Commands:\n"
            "  introspect          Print raw D-Bus introspection XML\n"
            "  list                List all item labels and UserName attributes\n"
            "  lookup <key>        Print the secret for the item with label <key>\n"
        ),
    )
    parser.add_argument(
        "--collection", default=DEFAULT_COLLECTION, metavar="PATH",
        help=f"Collection D-Bus path (default: {DEFAULT_COLLECTION})",
    )

    sub = parser.add_subparsers(dest="command")

    sub.add_parser("introspect", help="Print raw D-Bus introspection XML")

    p_list = sub.add_parser("list", help="List all items")
    p_list.add_argument(
        "--verbose", action="store_true",
        help="Show all attributes for each item",
    )

    p_lookup = sub.add_parser("lookup", help="Look up a secret by label")
    p_lookup.add_argument("key", help="Entry label (title) to look up")

    args = parser.parse_args()

    if args.command is None:
        parser.print_help()
        sys.exit(0)

    dispatch = {
        "introspect": cmd_introspect,
        "list":       cmd_list,
        "lookup":     cmd_lookup,
    }
    sys.exit(dispatch[args.command](args))


if __name__ == "__main__":
    main()
